    //先++\n        this->m_Num++;  \n        retun *this;\n    }\n    \n    //后置,利用占位参数,可以区分前置和后置\n    //返回的结果是值\n    MyInteger operator++(int){\n        // 先记录之前的结果\n        MyInteger temp = *this;  //局部变量,需要用值返回\n        \n        //再让m_Num++\n        this->m_Num++;\n        \n        //再返回记录的那个结果\n        return temp;\n    }\n    \nprivate:    \n    int m_Num;\n};\n\n//重载<<\nostream& operator<<(ostream& cout,const MyInteger& myInt){\n    cout << myInt.m_Num;\n    return cout; \n}\n\n//测试前置++\nvoid test01(){\n    MyInteger myInt;\n    cout << myInt << endl;\n    \n    cout << ++(++myInt) << endl;\n    cout << myInt << endl;\n}\n\n//测试后置++\nvoid test02(){\n    MyInteger myInt;\n    cout << myInt << endl;\n  \n    cout << myInt++ << endl;\n    cout << myInt << endl;\n}\n\nvoid testInt(){\n    int a = 0;\n    //测试内置数据类型的前置++与后置++\n    cout << ++(++a) << endl;  //2\n    cout << (a++)++ << endl;  //1,不支持一直后置++\n    cout << a << endl;   //2\n}\n")])])]),a("blockquote",[a("p",[a("strong",[a("font",{attrs:{color:"red"}},[t._v("优先使用++和--的标准形式，优先调用前置++。")])],1)]),t._v(" "),a("p",[t._v("​\t\t如果定义了++c，也要定义c++，递增操作符比较麻烦，因为他们都有前缀和后缀形式，而两种语义略有不同。重载operator++和operator--时应该模仿他们对应的内置操作符。")]),t._v(" "),a("p",[t._v("​\t对于++和--而言，后置形式是先返回，然后对象++或者--，返回的是对象的原值。前置形式，对象先++或--，返回当前对象，返回的是新对象。其标准形式为:")]),t._v(" "),a("center",[a("img",{staticStyle:{zoom:"100%"},attrs:{src:s(382),alt:"递增递减运算符重载"}})]),t._v(" "),a("p",[t._v("​\t\t调用代码时候，要优先使用前缀形式，除非确实需要后缀形式返回的原值，前缀和后缀形式语义上是等价的，输入工作量也相当，只是效率经常会略高一些，由于前缀形式少创建了一个临时对象。")])],1),t._v(" "),a("h4",{attrs:{id:"_4-7-5-指针运算符-、-重载"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#_4-7-5-指针运算符-、-重载"}},[t._v("#")]),t._v(" 4.7.5 指针运算符(*、->)重载")]),t._v(" "),a("blockquote",[a("p",[t._v("称为智能指针。")]),t._v(" "),a("p",[t._v("智能：如果我们不想写delete，可以利用智能指针，进行托管new出来的对象，即通过智能指针类维护new出来的对象，并且智能指针对象在释放的时候会将维护的new的对象也释放掉。")]),t._v(" "),a("p",[t._v("指针：通过重载 -> 和*操作符，可以将智能指针对象像指针一样使用。")])]),t._v(" "),a("div",{staticClass:"language-c++ extra-class"},[a("pre",{pre:!0,attrs:{